class Solution:
    def minIncrementForUnique(self, nums):
        # counting sort oracle
        if not nums:
            return 0
        max_val = max(nums) + len(nums) + 1
        count = [0] * (max_val + 1)
        for v in nums:
            count[v] += 1
        moves = 0
        for i in range(len(count)):
            if count[i] > 1:
                extra = count[i] - 1
                count[i + 1] += extra
                moves += extra
        return moves

