var minIncrementForUnique = function(nums) {
    nums.sort((a, b) => a - b);
    let moves = 0, prev = -1;
    for (const v of nums) {
        if (v <= prev) {
            moves += prev + 1 - v;
            prev++;
        } else {
            prev = v;
        }
    }
    return moves;
};
